# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 0;
    public int level = 1;
    public int experience = 0;
    public float attackDamage = 10f;
    public float defense = 5f;

    void Start()
    {
        health = maxHealth;
    }

    public void TakeDamage(int damage)
    {
        int calculatedDamage = Mathf.Max(0, damage - (int)defense);
        health -= calculatedDamage;
        
        if (health <= 0)
        {
            health = 0;
            Die();
        }
    }

    public void Heal(int amount)
    {
        health += amount;
        if (health > maxHealth)
        {
            health = maxHealth;
        }
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            return true;
        }
        return false;
    }

    public void AddExperience(int amount)
    {
        experience += amount;
        CheckLevelUp();
    }

    void CheckLevelUp()
    {
        int requiredExp = level * 100;
        if (experience >= requiredExp)
        {
            level++;
            experience -= requiredExp;
            maxHealth += 20;
            health = maxHealth;
            attackDamage += 2f;
            defense += 1f;
        }
    }

    void Die()
    {
        Debug.Log("Player died!");
    }

    public int CalculateDamageToEnemy(int enemyDefense)
    {
        int damage = (int)attackDamage - enemyDefense;
        return Mathf.Max(1, damage);
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int maxHealth = 50;
    public int damage = 15;
    public int defense = 2;
    public int currencyReward = 10;
    public int experienceReward = 25;

    PlayerStats player;

    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
    }

    public void TakeDamage(int damage)
    {
        int calculatedDamage = Mathf.Max(1, damage - defense);
        health -= calculatedDamage;

        if (health <= 0)
        {
            Die();
        }
    }

    void Die()
    {
        if (player != null)
        {
            player.AddCurrency(currencyReward);
            player.AddExperience(experienceReward);
        }
        Destroy(gameObject);
    }

    public void AttackPlayer()
    {
        if (player != null)
        {
            player.TakeDamage(damage);
        }
    }
}

public class ShopItem
{
    public string itemName;
    public int price;
    public string itemType;
    public int value;

    public ShopItem(string name, int price, string type, int value)
    {
        this.itemName = name;
        this.price = price;
        this.itemType = type;
        this.value = value;
    }
}

public class ShopManager : MonoBehaviour
{
    PlayerStats player;
    public ShopItem[] shopItems;

    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
        InitializeShop();
    }

    void InitializeShop()
    {
        shopItems = new ShopItem[]
        {
            new ShopItem("Health Potion", 50, "heal", 30),
            new ShopItem("Greater Health Potion", 100, "heal", 75),
            new ShopItem("Sword Upgrade", 200, "damage", 5),
            new ShopItem("Armor Upgrade", 150, "defense", 3),
            new ShopItem("Max Health Boost", 250, "maxHealth", 25),
            new ShopItem("Small Currency Pack", 100, "currency", 150),
            new ShopItem("Large Currency Pack", 500, "currency", 1000)
        };
    }

    public bool PurchaseItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Length)
        {
            return false;
        }

        ShopItem item = shopItems[itemIndex];
        int calculatedPrice = CalculatePrice(item.price, player.level);

        if (player.SpendCurrency(calculatedPrice))
        {
            ApplyItemEffect(item);
            return true;
        }

        return false;
    }

    int CalculatePrice(int basePrice, int playerLevel)
    {
        float priceMultiplier = 1f + (playerLevel - 1) * 0.1f;
        return (int)(basePrice * priceMultiplier);
    }

    void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case "heal":
                player.Heal(item.value);
                break;
            case "damage":
                player.attackDamage += item.value;
                break;
            case "defense":
                player.defense += item.value;
                break;
            case "maxHealth":
                player.maxHealth += item.value;
                break;
            case "currency":
                player.AddCurrency(item.value);
                break;
        }
    }

    public int GetItemPrice(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Length)
        {
            return 0;
        }
        return CalculatePrice(shopItems[itemIndex].price, player.level);
    }
}

public class CombatManager : MonoBehaviour
{
    PlayerStats player;

    void Start()
    {
        player = FindObjectOfType<PlayerStats>();
    }

    public void PlayerAttackEnemy(Enemy enemy)
    {
        if (enemy != null && player != null)
        {
            int damage = player.CalculateDamageToEnemy(enemy.defense);
            enemy.TakeDamage(damage);
        }
    }

    public void EnemyAttackPlayer(Enemy enemy)
    {
        if (enemy != null && player != null)
        {
            enemy.AttackPlayer();
        }
    }

    public int CalculateCriticalDamage(int baseDamage)
    {
        float critChance = 0.2f;
        if (Random.value < critChance)
        {
            return baseDamage * 2;
        }
        return baseDamage;
    }
}

